SELECT sku, path FROM products WHERE brand='Helios' AND series LIKE '%Helios Professional%' AND model='Helios 29A-FTE' AND name='Metal and Concrete Paint' AND json_extract(properties,'$.product_type')='metal paint' AND json_extract(properties,'$.color_family')='Green' LIMIT 10;
SELECT id, path, name FROM stores WHERE city='Vienna' ORDER BY id;
SELECT i.store_id, i.available_today FROM inventory i WHERE i.sku IN (SELECT sku FROM products WHERE brand='Helios' AND series LIKE '%Helios Professional%' AND model='Helios 29A-FTE' AND name='Metal and Concrete Paint' AND json_extract(properties,'$.product_type')='metal paint' AND json_extract(properties,'$.color_family')='Green') AND i.store_id IN (SELECT id FROM stores WHERE city='Vienna') ORDER BY i.store_id;

SELECT p.sku, p.path, p.brand, p.series, p.model, p.name FROM products p WHERE p.brand='Sonax' AND p.series LIKE '%Sonax Winter PRO%' AND p.model='198-6OA' AND p.name='Wiper Blade' AND json_extract(p.properties,'$.length')='400 mm' AND json_extract(p.properties,'$.adapter_type')='multi adapter' AND json_extract(p.properties,'$.vehicle_type')='car' LIMIT 10;
SELECT id, name, city FROM stores WHERE city='Vienna' ORDER BY id;
SELECT i.store_id, i.sku, i.available_today FROM inventory i JOIN stores s ON s.id=i.store_id WHERE s.city='Vienna' AND i.sku IN (SELECT p.sku FROM products p WHERE p.brand='Sonax' AND p.series LIKE '%Sonax Winter PRO%' AND p.model='198-6OA' AND p.name='Wiper Blade' AND json_extract(p.properties,'$.length')='400 mm' AND json_extract(p.properties,'$.adapter_type')='multi adapter' AND json_extract(p.properties,'$.vehicle_type')='car') ORDER BY i.store_id;
